 58→function ensureIndexedDb(): IDBFactory {
 59→  if (typeof indexedDB === 'undefined') {
 60→    throw new Error('IndexedDB is not available');
 61→  }
 62→  return indexedDB;
 63→}
 64→
 65→function requestToPromise<T>(request: IDBRequest<T>): Promise<T> {
 66→  return new Promise((resolve, reject) => {
 67→    request.onsuccess = () => resolve(request.result);
 68→    request.onerror = () => reject(request.error);
 69→  });
 70→}
 71→
 72→function transactionDone(tx: IDBTransaction): Promise<void> {
 73→  return new Promise((resolve, reject) => {
 74→    tx.oncomplete = () => resolve();
 75→    tx.onerror = () => reject(tx.error);
 76→    tx.onabort = () => reject(tx.error ?? new Error('IndexedDB transaction aborted'));
 77→  });
 78→}
 79→
 80→async function openDb(): Promise<IDBDatabase> {
 81→  const db = ensureIndexedDb();
 82→  return await new Promise<IDBDatabase>((resolve, reject) => {
 83→    const request = db.open(DB_NAME, DB_VERSION);
 84→    request.onupgradeneeded = () => {
 85→      const nextDb = request.result;
 86→      if (!nextDb.objectStoreNames.contains(STORE_NAME)) {
 87→        nextDb.createObjectStore(STORE_NAME, { keyPath: 'id' });
 88→      }
 89→      if (!nextDb.objectStoreNames.contains(SYNC_ERROR_STORE_NAME)) {
 90→        nextDb.createObjectStore(SYNC_ERROR_STORE_NAME, { keyPath: 'id' });
 91→      }
 92→    };
 93→    request.onsuccess = () => resolve(request.result);
 94→    request.onerror = () => reject(request.error);
 95→  });
 96→}
