122→export async function listQueueItems(): Promise<QueueItem[]> {
123→  const db = await openDb();
124→  const tx = db.transaction(STORE_NAME, 'readonly');
125→  const request = tx.objectStore(STORE_NAME).getAll();
126→  const result = await requestToPromise(request);
127→  await transactionDone(tx);
128→  db.close();
129→  return (result as QueueItem[]).sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime());
130→}
131→
132→async function updateItem(id: string, updater: (item: QueueItem) => QueueItem): Promise<QueueItem | null> {
133→  const db = await openDb();
134→  return await new Promise<QueueItem | null>((resolve, reject) => {
135→    const tx = db.transaction(STORE_NAME, 'readwrite');
136→    const store = tx.objectStore(STORE_NAME);
137→    let updated: QueueItem | null = null;
138→    const getRequest = store.get(id);
139→    getRequest.onsuccess = () => {
140→      const existing = getRequest.result as QueueItem | undefined;
141→      if (!existing) return;
142→      updated = updater(existing);
143→      store.put(updated);
144→    };
145→    getRequest.onerror = () => reject(getRequest.error);
146→    tx.oncomplete = () => {
147→      db.close();
148→      resolve(updated);
149→    };
150→    tx.onerror = () => {
151→      db.close();
152→      reject(tx.error);
153→    };
154→    tx.onabort = () => {
155→      db.close();
156→      reject(tx.error ?? new Error('IndexedDB transaction aborted'));
157→    };
158→  });
159→}
