 36→export interface QueueSyncSummary {
 37→  synced: number;
 38→  failed: number;
 39→  syncedIds: string[];
 40→  failedIds: string[];
 41→  permanentFailures: number;
 42→  permanentFailureIds: string[];
 43→  permanentFailureMessages: string[];
 44→  remaining: number;
 45→}
