 58→function ensureIndexedDb(): IDBFactory {
 59→  if (typeof indexedDB === 'undefined') {
 60→    throw new Error('IndexedDB is not available');
 61→  }
 62→  return indexedDB;
 63→}
 64→
 65→function requestToPromise<T>(request: IDBRequest<T>): Promise<T> {
 66→  return new Promise((resolve, reject) => {
 67→    request.onsuccess = () => resolve(request.result);
 68→    request.onerror = () => reject(request.error);
 69→  });
 70→}
 71→
 72→function transactionDone(tx: IDBTransaction): Promise<void> {
 73→  return new Promise((resolve, reject) => {
 74→    tx.oncomplete = () => resolve();
 75→    tx.onerror = () => reject(tx.error);
 76→    tx.onabort = () => reject(tx.error ?? new Error('IndexedDB transaction aborted'));
 77→  });
 78→}
 79→
 80→async function openDb(): Promise<IDBDatabase> {
 81→  const db = ensureIndexedDb();
 82→  return await new Promise<IDBDatabase>((resolve, reject) => {
 83→    const request = db.open(DB_NAME, DB_VERSION);
 84→    request.onupgradeneeded = () => {
 85→      const nextDb = request.result;
 86→      if (!nextDb.objectStoreNames.contains(STORE_NAME)) {
 87→        nextDb.createObjectStore(STORE_NAME, { keyPath: 'id' });
 88→      }
 89→      if (!nextDb.objectStoreNames.contains(SYNC_ERROR_STORE_NAME)) {
 90→        nextDb.createObjectStore(SYNC_ERROR_STORE_NAME, { keyPath: 'id' });
 91→      }
 92→    };
 93→    request.onsuccess = () => resolve(request.result);
 94→    request.onerror = () => reject(request.error);
 95→  });
 96→}
 97→
 98→async function putItem(item: QueueItem): Promise<void> {
 99→  const db = await openDb();
100→  const tx = db.transaction(STORE_NAME, 'readwrite');
101→  tx.objectStore(STORE_NAME).put(item);
102→  await transactionDone(tx);
103→  db.close();
104→}
105→
106→export async function enqueueSubmission(payload: SubmissionInput): Promise<QueueItem> {
107→  const now = new Date().toISOString();
108→  const item: QueueItem = {
109→    id: crypto.randomUUID(),
110→    idempotencyKey: crypto.randomUUID(),
111→    payload,
112→    status: 'pending',
113→    attempts: 0,
114→    retryCount: 0,
115→    createdAt: now,
116→    updatedAt: now
117→  };
118→  await putItem(item);
119→  return item;
120→}
121→
122→export async function listQueueItems(): Promise<QueueItem[]> {
123→  const db = await openDb();
124→  const tx = db.transaction(STORE_NAME, 'readonly');
125→  const request = tx.objectStore(STORE_NAME).getAll();
126→  const result = await requestToPromise(request);
127→  await transactionDone(tx);
128→  db.close();
129→  return (result as QueueItem[]).sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime());
130→}
131→
132→async function updateItem(id: string, updater: (item: QueueItem) => QueueItem): Promise<QueueItem | null> {
133→  const db = await openDb();
134→  return await new Promise<QueueItem | null>((resolve, reject) => {
135→    const tx = db.transaction(STORE_NAME, 'readwrite');
136→    const store = tx.objectStore(STORE_NAME);
137→    let updated: QueueItem | null = null;
138→    const getRequest = store.get(id);
139→    getRequest.onsuccess = () => {
140→      const existing = getRequest.result as QueueItem | undefined;
141→      if (!existing) return;
142→      updated = updater(existing);
143→      store.put(updated);
144→    };
145→    getRequest.onerror = () => reject(getRequest.error);
146→    tx.oncomplete = () => {
147→      db.close();
148→      resolve(updated);
149→    };
150→    tx.onerror = () => {
151→      db.close();
152→      reject(tx.error);
153→    };
154→    tx.onabort = () => {
155→      db.close();
156→      reject(tx.error ?? new Error('IndexedDB transaction aborted'));
157→    };
158→  });
159→}
