203→
204→export async function flushOfflineQueue(
205→  sendFn: (payload: SubmissionInput, options?: { idempotencyKey?: string }) => Promise<void>,
206→): Promise<QueueSyncSummary> {
207→  const items = await listQueueItems();
208→  const now = Date.now();
209→  let synced = 0;
210→  let failed = 0;
211→  const syncedIds: string[] = [];
212→  const failedIds: string[] = [];
213→  let permanentFailures = 0;
214→  const permanentFailureIds: string[] = [];
215→  const permanentFailureMessages = new Set<string>();
216→
217→  for (const item of items) {
218→    // Skip items not yet ready for retry (exponential backoff).
219→    if (item.nextRetryAt && new Date(item.nextRetryAt).getTime() > now) {
220→      failed += 1;
221→      failedIds.push(item.id);
222→      continue;
223→    }
224→
225→    await updateItem(item.id, (current) => ({
226→      ...current,
227→      status: 'syncing',
228→      attempts: current.attempts + 1,
229→      updatedAt: new Date().toISOString()
230→    }));
231→
232→    try {
233→      await sendFn(item.payload, { idempotencyKey: item.idempotencyKey });
234→      await removeItem(item.id);
235→      synced += 1;
236→      syncedIds.push(item.id);
237→    } catch (error) {
238→      const details = toQueueErrorInfo(error);
239→      if (details.retryable) {
240→        failed += 1;
241→        failedIds.push(item.id);
242→        const retryCount = (item.retryCount ?? 0) + 1;
243→        const baseDelay = Math.min(30000, 1000 * Math.pow(2, retryCount));
244→        const jitter = Math.random() * 1000;
245→        const nextRetryAt = new Date(now + baseDelay + jitter).toISOString();
246→        await updateItem(item.id, (current) => ({
247→          ...current,
248→          status: 'failed',
249→          retryCount,
250→          nextRetryAt,
251→          updatedAt: new Date().toISOString(),
252→          lastError: details.message,
253→        }));
254→        continue;
255→      }
256→
257→      permanentFailures += 1;
258→      permanentFailureIds.push(item.id);
259→      permanentFailureMessages.add(details.message);
260→      await putSyncErrorRecord({
261→        id: crypto.randomUUID(),
262→        queueItemId: item.id,
263→        message: details.message,
264→        createdAt: new Date().toISOString(),
265→        payloadSummary: {
266→          eventType: item.payload.eventType,
267→          category: item.payload.category,
268→          pointId: item.payload.pointId,
269→          location: item.payload.location,
270→        },
271→      });
272→      await removeItem(item.id);
273→    }
274→  }
275→
276→  const remaining = (await listQueueItems()).length;
277→  return {
278→    synced,
279→    failed,
280→    syncedIds,
281→    failedIds,
282→    permanentFailures,
283→    permanentFailureIds,
284→    permanentFailureMessages: Array.from(permanentFailureMessages),
285→    remaining,
286→  };
287→}
