  1→import { apiFetch } from './api';
  2→import type { SubmissionInput } from '../../shared/types';
  3→import { getClientDeviceInfo } from './deviceProfile';
  4→import { sanitizeErrorMessage as sanitizeBase } from './errorUtils';
  5→
  6→const DEFAULT_SYNC_ERROR = 'Unable to sync submission right now.';
  7→
  8→function sanitizeErrorMessage(input: unknown, fallback = DEFAULT_SYNC_ERROR): string {
  9→  const result = sanitizeBase(input, fallback);
 10→  return result === fallback ? fallback : result.replace(/^Error:\s*/i, '');
 11→}
 12→
 13→async function extractResponseMessage(response: Response): Promise<string> {
 14→  const fallback = response.statusText || DEFAULT_SYNC_ERROR;
 15→  const contentType = response.headers.get('content-type')?.toLowerCase() ?? '';
 16→
 17→  if (contentType.includes('application/json')) {
 18→    try {
 19→      const payload = (await response.json()) as { error?: unknown; message?: unknown };
 20→      return sanitizeErrorMessage(payload?.error ?? payload?.message, fallback);
 21→    } catch {
 22→      return fallback;
 23→    }
 24→  }
 25→
 26→  try {
 27→    const text = await response.text();
 28→    return sanitizeErrorMessage(text, fallback);
 29→  } catch {
 30→    return fallback;
 31→  }
 32→}
 33→
 34→function isRetryableStatus(status: number): boolean {
 35→  if (status === 408 || status === 425 || status === 429) return true;
 36→  return status >= 500;
 37→}
 38→
 39→export class SubmissionSyncError extends Error {
 40→  retryable: boolean;
 41→  status: number | null;
 42→
 43→  constructor(
 44→    message: string,
 45→    options: {
 46→      retryable?: boolean;
 47→      status?: number | null;
 48→      cause?: unknown;
 49→    } = {},
 50→  ) {
 51→    super(message);
 52→    this.name = 'SubmissionSyncError';
 53→    this.retryable = Boolean(options.retryable);
 54→    this.status = options.status ?? null;
 55→    if (options.cause !== undefined) {
 56→      (this as Error & { cause?: unknown }).cause = options.cause;
 57→    }
 58→  }
 59→}
 60→
 61→export function toSubmissionSyncError(error: unknown): SubmissionSyncError {
 62→  if (error instanceof SubmissionSyncError) return error;
 63→  if (error instanceof Error) {
 64→    return new SubmissionSyncError(sanitizeErrorMessage(error.message), { retryable: true, cause: error });
 65→  }
 66→  return new SubmissionSyncError(DEFAULT_SYNC_ERROR, { retryable: true, cause: error });
 67→}
 68→
 69→function withClientDevice(payload: SubmissionInput): SubmissionInput {
 70→  const details =
 71→    payload.details && typeof payload.details === 'object'
 72→      ? { ...(payload.details as Record<string, unknown>) }
 73→      : {};
 74→  if (!details.clientDevice) {
 75→    details.clientDevice = getClientDeviceInfo();
 76→  }
 77→  return { ...payload, details };
 78→}
 79→
 80→export async function sendSubmissionPayload(payload: SubmissionInput, options?: { idempotencyKey?: string }): Promise<void> {
 81→  const enrichedPayload = withClientDevice(payload);
 82→  const headers: Record<string, string> = { 'Content-Type': 'application/json' };
 83→  if (options?.idempotencyKey) {
 84→    headers['X-Idempotency-Key'] = options.idempotencyKey;
 85→  }
 86→  let response: Response;
 87→  try {
 88→    response = await apiFetch('/api/submissions', {
 89→      method: 'POST',
 90→      headers,
 91→      body: JSON.stringify(enrichedPayload),
 92→    });
 93→  } catch (error) {
 94→    throw new SubmissionSyncError(DEFAULT_SYNC_ERROR, { retryable: true, cause: error });
 95→  }
 96→
 97→  if (response.ok) return;
 98→
 99→  const message = await extractResponseMessage(response);
100→  throw new SubmissionSyncError(message, {
101→    retryable: isRetryableStatus(response.status),
102→    status: response.status,
103→  });
104→}
