 14→// Fields to skip when comparing details between snapshots
 15→const SKIP_FIELDS = new Set([
 16→  "fraudCheck",
 17→  "clientDevice",
 18→  "source",
 19→  "externalId",
 20→  "isImported",
 21→  "hasPhoto",
 22→  "hasSecondaryPhoto",
