263→// ── DB operations ─────────────────────────────────────────────────────
264→
265→async function insertSnapshotRows(rows: SnapshotRow[]): Promise<number> {
266→  if (rows.length === 0) return 0;
267→  const batchSize = 200;
268→  let inserted = 0;
269→  for (let i = 0; i < rows.length; i += batchSize) {
270→    const batch = rows.slice(i, i + batchSize);
271→    const values: unknown[] = [];
272→    const placeholders = batch.map((row, idx) => {
273→      const base = idx * 13;
274→      values.push(
275→        row.snapshotDate,
276→        row.verticalId,
277→        row.pointId,
278→        row.category,
279→        row.siteName,
280→        row.latitude,
281→        row.longitude,
282→        JSON.stringify(row.details),
283→        row.gaps,
284→        row.eventsCount,
285→        row.photoUrl,
286→        row.source,
287→        row.externalId,
288→      );
289→      return `($${base + 1},$${base + 2},$${base + 3},$${base + 4},$${base + 5},$${base + 6},$${base + 7},$${base + 8},$${base + 9},$${base + 10},$${base + 11},$${base + 12},$${base + 13})`;
290→    });
291→    const result = await query(
292→      `INSERT INTO snapshots (snapshot_date, vertical_id, point_id, category, site_name, latitude, longitude, details, gaps, events_count, photo_url, source, external_id)
293→       VALUES ${placeholders.join(",")}
294→       ON CONFLICT (snapshot_date, point_id) DO NOTHING`,
295→      values,
296→    );
297→    inserted += result.rowCount ?? 0;
298→  }
299→  return inserted;
300→}
301→
302→async function insertDeltaRows(rows: DeltaRow[]): Promise<number> {
303→  if (rows.length === 0) return 0;
304→  const batchSize = 200;
305→  let inserted = 0;
306→  for (let i = 0; i < rows.length; i += batchSize) {
307→    const batch = rows.slice(i, i + batchSize);
308→    const values: unknown[] = [];
309→    const placeholders = batch.map((row, idx) => {
310→      const base = idx * 11;
311→      values.push(
312→        row.snapshotDate,
313→        row.baselineSnapshotDate,
314→        row.verticalId,
315→        row.pointId,
316→        row.deltaType,
317→        row.deltaField,
318→        row.previousValue,
319→        row.currentValue,
320→        row.deltaMagnitude,
321→        row.deltaDirection,
322→        row.deltaSummary,
323→      );
324→      return `($${base + 1},$${base + 2},$${base + 3},$${base + 4},$${base + 5},$${base + 6},$${base + 7},$${base + 8},$${base + 9},$${base + 10},$${base + 11})`;
325→    });
326→    const result = await query(
327→      `INSERT INTO snapshot_deltas (snapshot_date, baseline_snapshot_date, vertical_id, point_id, delta_type, delta_field, previous_value, current_value, delta_magnitude, delta_direction, delta_summary)
328→       VALUES ${placeholders.join(",")}`,
329→      values,
330→    );
331→    inserted += result.rowCount ?? 0;
332→  }
333→  return inserted;
334→}
