280→function shouldRunFallbackFraudCheck(event: PointEvent, fraudCheck: SubmissionFraudCheck | null): boolean {
281→  const primaryUrl = typeof event.photoUrl === "string" ? event.photoUrl.trim() : "";
282→  const secondaryUrl = getSecondaryPhotoUrl(event);
283→  if (!fraudCheck) return Boolean(primaryUrl || secondaryUrl);
284→  if (primaryUrl && isPhotoMetadataEffectivelyEmpty(fraudCheck.primaryPhoto)) return true;
285→  if (secondaryUrl && isPhotoMetadataEffectivelyEmpty(fraudCheck.secondaryPhoto)) return true;
286→  return false;
287→}
288→
289→function mergePhotoFraudMetadata(
290→  existing: SubmissionFraudCheck["primaryPhoto"],
291→  recovered: SubmissionFraudCheck["primaryPhoto"],
292→  hasPhotoUrl: boolean,
293→): SubmissionFraudCheck["primaryPhoto"] {
294→  if (!hasPhotoUrl) return existing ?? null;
295→  if (existing && !isPhotoMetadataEffectivelyEmpty(existing)) return existing;
296→  if (recovered) return recovered;
297→  return existing ?? null;
298→}
299→
300→async function buildFallbackFraudCheck(
301→  event: PointEvent,
302→  existingFraudCheck: SubmissionFraudCheck | null,
303→): Promise<SubmissionFraudCheck | null> {
304→  const primaryUrl = typeof event.photoUrl === "string" ? event.photoUrl.trim() : "";
305→  const secondaryUrl = getSecondaryPhotoUrl(event);
306→  if (!primaryUrl && !secondaryUrl) return existingFraudCheck;
307→
308→  const needsPrimaryRecovery = Boolean(primaryUrl) && isPhotoMetadataEffectivelyEmpty(existingFraudCheck?.primaryPhoto);
309→  const needsSecondaryRecovery = Boolean(secondaryUrl) && isPhotoMetadataEffectivelyEmpty(existingFraudCheck?.secondaryPhoto);
310→  const primaryExtracted = needsPrimaryRecovery ? await extractPhotoMetadataFromUrl(primaryUrl) : null;
311→  const secondaryExtracted = needsSecondaryRecovery ? await extractPhotoMetadataFromUrl(secondaryUrl) : null;
312→  const recoveredPrimaryPhoto = buildPhotoFraudMetadata({
313→    extracted: primaryExtracted,
314→    submissionLocation: event.location,
315→    ipLocation: null,
316→    submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
317→    ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
318→  });
319→  const recoveredSecondaryPhoto = buildPhotoFraudMetadata({
320→    extracted: secondaryExtracted,
321→    submissionLocation: event.location,
322→    ipLocation: null,
323→    submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
324→    ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
325→  });
326→  const primaryPhoto = mergePhotoFraudMetadata(existingFraudCheck?.primaryPhoto ?? null, recoveredPrimaryPhoto, Boolean(primaryUrl));
327→  const secondaryPhoto = mergePhotoFraudMetadata(
328→    existingFraudCheck?.secondaryPhoto ?? null,
329→    recoveredSecondaryPhoto,
330→    Boolean(secondaryUrl),
331→  );
332→  if (!primaryPhoto && !secondaryPhoto) return null;
333→
334→  return buildSubmissionFraudCheck({
335→    submissionLocation: existingFraudCheck?.submissionLocation ?? event.location,
336→    effectiveLocation: existingFraudCheck?.effectiveLocation ?? event.location,
337→    ipLocation: existingFraudCheck?.ipLocation ?? null,
338→    primaryPhoto,
339→    secondaryPhoto,
340→    submissionMatchThresholdKm: existingFraudCheck?.submissionMatchThresholdKm ?? SUBMISSION_PHOTO_MATCH_KM,
341→    ipMatchThresholdKm: existingFraudCheck?.ipMatchThresholdKm ?? IP_PHOTO_MATCH_KM,
342→  });
343→}
