258→async function getUserProfilesBatch(ids: string[]): Promise<Map<string, UserProfile>> {
259→  if (!ids.length) return new Map();
260→  const normalizedIds = ids.map(normalizeUserId);
261→
262→  const fetchRows = async (includePhone: boolean): Promise<UserProfile[]> => {
263→    const cols = includePhone
264→      ? "id, email, phone, name, image, occupation, xp, password_hash, is_admin, map_scope"
265→      : "id, email, name, image, occupation, xp, password_hash, is_admin, map_scope";
266→    const result = await query<Record<string, unknown>>(
267→      `select ${cols} from user_profiles where id = ANY($1::text[])`,
268→      [normalizedIds],
269→    );
270→    return result.rows.map(rowToUserProfile);
271→  };
272→
273→  let rows: UserProfile[];
274→  if (phoneColumnState === "missing") {
275→    rows = await fetchRows(false);
276→  } else {
277→    try {
278→      rows = await fetchRows(true);
279→      if (phoneColumnState === "unknown") phoneColumnState = "present";
280→    } catch (error) {
281→      if (!isMissingPhoneColumnError(error)) throw error;
282→      phoneColumnState = "missing";
283→      rows = await fetchRows(false);
284→    }
