  3→const NETWORK_ERROR_CODES = new Set([
  4→  "ECONNREFUSED",
  5→  "ECONNRESET",
  6→  "EHOSTUNREACH",
  7→  "ENETUNREACH",
  8→  "ENOTFOUND",
