 88→async function extractResponseErrorPayload(response: Response, fallback: string): Promise<ApiErrorPayload> {
 89→  const contentType = response.headers.get("content-type")?.toLowerCase() ?? "";
 90→  if (contentType.includes("application/json")) {
 91→    const payload = await safeReadJson<{ error?: unknown; message?: unknown; code?: unknown }>(response);
 92→    if (payload) {
 93→      const message = sanitizeErrorMessage(payload.error ?? payload.message, fallback);
 94→      const code = typeof payload.code === "string" && payload.code.trim() ? payload.code.trim() : undefined;
 95→      return { message, code };
 96→    }
 97→    return { message: fallback };
