578→export function applyClientExifFallback(
579→  metadata: ExtractedPhotoMetadata,
580→  clientExif: ClientExifData | null | undefined,
581→): ExtractedPhotoMetadata {
582→  if (!clientExif) return metadata;
583→
584→  const fallbackGps: SubmissionLocation | null =
585→    typeof clientExif.latitude === "number" &&
586→    typeof clientExif.longitude === "number" &&
587→    Number.isFinite(clientExif.latitude) &&
588→    Number.isFinite(clientExif.longitude)
589→      ? { latitude: clientExif.latitude, longitude: clientExif.longitude }
590→      : null;
591→
592→  const fallbackCapturedAt =
593→    typeof clientExif.capturedAt === "string" && clientExif.capturedAt.trim() ? clientExif.capturedAt.trim() : null;
594→  const fallbackDeviceMake =
595→    typeof clientExif.deviceMake === "string" && clientExif.deviceMake.trim() ? clientExif.deviceMake.trim() : null;
596→  const fallbackDeviceModel =
597→    typeof clientExif.deviceModel === "string" && clientExif.deviceModel.trim() ? clientExif.deviceModel.trim() : null;
598→
599→  const supplementedFields: string[] = [];
600→  const gps = metadata.gps ?? fallbackGps;
601→  if (!metadata.gps && fallbackGps) supplementedFields.push("gps");
602→  const capturedAt = metadata.capturedAt ?? fallbackCapturedAt;
603→  if (!metadata.capturedAt && fallbackCapturedAt) supplementedFields.push("capturedAt");
604→  const deviceMake = metadata.deviceMake ?? fallbackDeviceMake;
605→  if (!metadata.deviceMake && fallbackDeviceMake) supplementedFields.push("deviceMake");
606→  const deviceModel = metadata.deviceModel ?? fallbackDeviceModel;
607→  if (!metadata.deviceModel && fallbackDeviceModel) supplementedFields.push("deviceModel");
608→
609→  if (supplementedFields.length === 0) return metadata;
610→
611→  return {
612→    gps,
613→    capturedAt,
614→    deviceMake,
615→    deviceModel,
616→    exifStatus: "fallback_recovered",
617→    exifReason: `EXIF supplemented from client-side metadata for fields: ${supplementedFields.join(", ")} (server source=${metadata.exifSource}; status=${metadata.exifStatus}; reason=${metadata.exifReason ?? "no details"})`,
618→    exifSource: "client_fallback",
619→  };
620→}
