 50→  const formatHistoryDate = (iso: string) => {
 51→    const date = new Date(iso);
 52→    if (Number.isNaN(date.getTime())) return t('Unknown', 'Inconnu');
 53→
 54→    const now = new Date();
 55→    const sameDay = now.toDateString() === date.toDateString();
 56→    const yesterday = new Date(now);
 57→    yesterday.setDate(now.getDate() - 1);
 58→    const isYesterday = yesterday.toDateString() === date.toDateString();
 59→    const time = date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
 60→
 61→    if (sameDay) return language === 'fr' ? `Aujourd'hui • ${time}` : `Today • ${time}`;
 62→    if (isYesterday) return language === 'fr' ? `Hier • ${time}` : `Yesterday • ${time}`;
