1002→        reason: `A ${params.category} already exists ${Math.round(distKm * 1000)}m away (${point.name}). Did you mean to enrich it?`,
1003→      };
1004→    }
1005→
1006→    // ── PROXIMITY + NAME MATCH ──
1007→    if (distKm < thresholds.flagKm && nameSimilarity > 0.7) {
1008→      return {
1009→        isDuplicate: true,
1010→        matchType: 'proximity_name',
1011→        matchedPointId: point.pointId,
1012→        confidence: 85,
1013→        action: 'suggest_enrich',
1014→        reason: `"${point.name}" already exists ${Math.round(distKm * 1000)}m away with ${Math.round(nameSimilarity * 100)}% name similarity`,
1015→      };
1016→    }
1017→
1018→    // ── PROXIMITY FLAG ──
1019→    if (distKm < thresholds.flagKm) {
1020→      return {
1021→        isDuplicate: true,
1022→        matchType: 'proximity_name',
1023→        matchedPointId: point.pointId,
1024→        confidence: 60,
1025→        action: 'flag',
1026→        reason: `Another ${params.category} exists ${Math.round(distKm * 1000)}m away (${point.name}). Possibly a duplicate.`,
1027→      };
1028→    }
1029→
1030→    // ── ENRICH SUGGESTION ZONE ──
1031→    if (distKm < thresholds.enrichSuggestKm && nameSimilarity > 0.8) {
1032→      return {
1033→        isDuplicate: true,
